import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import axios from 'axios';

const Dashboard = () => {
  const navigate = useNavigate();
  const [syllabus, setSyllabus] = useState('');
  const [targetDate, setTargetDate] = useState('');
  const [schedule, setSchedule] = useState(null); 
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    const token = localStorage.getItem('token');
    if (!token) {
      navigate('/login');
    } else {
      const savedSchedule = localStorage.getItem('studyPulse_schedule');
      if (savedSchedule) {
        setSchedule(JSON.parse(savedSchedule));
      }
    }
  }, [navigate]);

  const handleLogout = () => {
    localStorage.removeItem('token');
    localStorage.removeItem('studyPulse_schedule');
    navigate('/login');
  };

  const generateSchedule = async () => {
    if (!syllabus || !targetDate) {
      alert("Please enter both the syllabus and a target date!");
      return;
    }
    setLoading(true);
    
    // Simulate AI Generation
    setTimeout(() => {
      const topics = syllabus.split(',').map(item => item.trim());
      const generatedDays = topics.map((topic, index) => ({
        _id: `temp_${index}`, // Replace with real DB IDs after backend sync
        day: index + 1,
        topic: topic || `Topic ${index + 1}`,
        status: 'pending',
        date: new Date(Date.now() + index * 86400000).toLocaleDateString()
      }));

      setSchedule(generatedDays);
      localStorage.setItem('studyPulse_schedule', JSON.stringify(generatedDays));
      setLoading(false);
      navigate('/planPage'); // Move to PlanPage immediately after generation
    }, 1500);
  };

  return (
    <div style={{ fontFamily: 'Arial, sans-serif', backgroundColor: '#f9f9f9', minHeight: '100vh' }}>
      <nav style={{ display: 'flex', justifyContent: 'space-between', padding: '15px 30px', background: '#2c3e50', color: 'white' }}>
        <h2 style={{ margin: 0 }}>StudyPulse</h2>
        <button onClick={handleLogout} style={{ background: '#e74c3c', color: 'white', border: 'none', padding: '8px 15px', borderRadius: '5px', cursor: 'pointer' }}>Logout</button>
      </nav>

      <div style={{ maxWidth: '600px', margin: '40px auto', padding: '30px', background: 'white', borderRadius: '10px', boxShadow: '0 4px 6px rgba(0,0,0,0.1)' }}>
        {!schedule ? (
          <div style={{ display: 'flex', flexDirection: 'column', gap: '15px' }}>
            <h1>Create Your Plan</h1>
            <label>Exam/Target Date:</label>
            <input type="date" value={targetDate} onChange={(e) => setTargetDate(e.target.value)} style={{ padding: '10px', borderRadius: '5px', border: '1px solid #ddd' }} />
            <label>Syllabus Topics (Comma separated):</label>
            <textarea placeholder="React, Node.js, Express..." value={syllabus} onChange={(e) => setSyllabus(e.target.value)} style={{ height: '120px', padding: '10px', borderRadius: '5px', border: '1px solid #ddd' }} />
            <button onClick={generateSchedule} disabled={loading} style={{ backgroundColor: loading ? '#bdc3c7' : '#3498db', color: 'white', padding: '15px', borderRadius: '5px', cursor: 'pointer', border: 'none' }}>
              {loading ? 'Generating AI Schedule...' : 'Generate Plan'}
            </button>
          </div>
        ) : (
          <div style={{ textAlign: 'center' }}>
            <h2>Plan Generated!</h2>
            <button onClick={() => navigate('/planPage')} style={{ padding: '10px 20px', background: '#2ecc71', color: 'white', border: 'none', borderRadius: '5px', cursor: 'pointer' }}>View My Plan</button>
          </div>
        )}
      </div>
    </div>
  );
};

export default Dashboard;
